<?php
namespace App\Domain\Admin\Content;
use App\Domain\Inventory\Instances\Refinement\RefinementRuleValidator;use App\Domain\WorldCatalog\CatalogStatus;use App\Models\Item;use App\Models\RefinementLevel;use App\Models\RefinementLevelMaterial;use Illuminate\Support\Facades\DB;use InvalidArgumentException;
final class RefinementContentService {private $validator;public function __construct(RefinementRuleValidator $validator){$this->validator=$validator;}public function saveRule(array $data,RefinementLevel $rule=null){return DB::transaction(function()use($data,$rule){$model=$rule?:new RefinementLevel();$candidate=new RefinementLevel($data);$this->validator->validate($candidate);$duplicate=RefinementLevel::where('from_level',$data['from_level'])->when($model->exists,function($q)use($model){$q->whereKeyNot($model->id);})->exists();if($duplicate)throw new InvalidArgumentException('Ya existe una regla para ese nivel.');$model->fill($data);$model->save();return$model;});}public function deactivate(RefinementLevel $rule){$rule->update(['status'=>CatalogStatus::INACTIVE]);}public function saveMaterial(RefinementLevel $rule,array $data,RefinementLevelMaterial $line=null){return DB::transaction(function()use($rule,$data,$line){$item=Item::findOrFail($data['item_id']);$this->validator->validateMaterial($item,(int)$data['quantity']);$duplicate=RefinementLevelMaterial::where('refinement_level_id',$rule->id)->where('item_id',$item->id)->when($line&&$line->exists,function($q)use($line){$q->whereKeyNot($line->id);})->exists();if($duplicate)throw new InvalidArgumentException('El material ya pertenece a la regla.');$model=$line?:new RefinementLevelMaterial(['refinement_level_id'=>$rule->id]);$model->fill($data);$model->save();return$model;});}public function removeMaterial(RefinementLevelMaterial $line){$line->delete();}}
